// DALL-E binary'yi al ve metadata ekle
const items = $input.all();

// Binary data kontrol
if (!items[0].binary || !items[0].binary.data) {
  throw new Error('DALL-E binary data bulunamadı!');
}

// Reference node'dan bilgileri al
const referenceNode = $('Download –  Reference Image').item.json;
const gorselId = referenceNode.gorsel_id || 'generated';
const fileName = `${gorselId}_output.png`;

// n8n binary'yi direkt kullan, sadece filename'i değiştir
const binaryData = items[0].binary.data;

return {
  json: {
    gorsel_id: gorselId,
    fileName: fileName,
    ana_prompt: referenceNode.ana_prompt,
    stil_prompt: referenceNode.stil_prompt
  },
  binary: {
    data: {
      ...binaryData,  // Mevcut binary data'yı koru
      fileName: fileName  // Sadece filename'i güncelle
    }
  }
};
